// Phase 7O (1/?) — Operational Readiness Audit smoke.
//
//   node scripts/smoke-operational-readiness-audit.mjs
//
// Locks:
//   - the audit script exists and is self-contained (pure node, no
//     network, no external deps)
//   - the audit report file exists and was regenerated by the script
//   - the report covers every spec'd audit area
//   - the report covers every spec'd route / endpoint check
//   - the report covers every spec'd report-registration check
//   - the report covers every spec'd export contract key
//   - the report covers every spec'd read-only boundary check
//   - the report includes the live-testing checklist
//   - the report headline is green (Blockers: 0) so CI can grep
//   - the audit script + report add NO new mutation behavior
//     anywhere in the code surface
//   - Phase 7F.4 / 7J.1 / 7M.1 regression guards still hold

import { readFileSync, statSync } from 'fs'
import { execSync } from 'child_process'

let passed = 0, failed = 0
function assert(cond, label, ctx) {
  if (cond) { passed++; console.log(`  ✓ ${label}`) }
  else { failed++; console.error(`  ✗ ${label}`); if (ctx !== undefined) console.error('    ctx:', JSON.stringify(ctx)) }
}

// ── 1. Audit script source contracts ─────────────────────────────────────
console.log('— scripts/audit-operational-readiness.mjs (source)')
{
  const src = readFileSync('scripts/audit-operational-readiness.mjs', 'utf8')

  // Script writes the report to the documented path.
  assert(/docs\/operational-readiness-audit\.md/.test(src),
    'script writes docs/operational-readiness-audit.md')
  assert(/writeFileSync\(/.test(src),
    'script uses writeFileSync() to emit the report')

  // Script is pure node — no fetch, no network, no React, no Store.
  const codeOnly = src
    .replace(/\/\*[\s\S]*?\*\//g, '')
    .replace(/^\s*\/\/.*$/gm, '')
  assert(!/\bfetch\(/.test(codeOnly),
    'audit script does not call fetch()')
  assert(!/from\s+['"]react['"]/.test(codeOnly),
    'audit script does not import react')
  assert(!/from\s+['"][^'"]*Store(\.js)?['"]/.test(codeOnly),
    'audit script imports no *Store module')

  // Audit script must never sneak in a mutation CALL. We detect
  // actual call sites (`verb(`) rather than mere mentions, because
  // the audit script legitimately enumerates these verb names as
  // string literals inside its own forbidden-write checks.
  for (const verb of [
    'createSpray', 'recordInventoryUsage', 'createCalendarEvent',
    'setProgramItemCompletedLink',
    'setInventoryCostBasis', 'patchInventoryCostBasis',
    'createBudgetEntry', 'createInvoice', 'createLedgerEntry',
  ]) {
    const re = new RegExp(`\\b${verb}\\s*\\(`)
    assert(!re.test(codeOnly),
      `audit script never calls ${verb}() (string-literal references are OK)`)
  }

  // Script always exits 0 so CI doesn't break on warnings.
  assert(/process\.exit\(0\)/.test(src),
    'audit script always exits with code 0')
}

// ── 2. Audit script runs cleanly + regenerates the report ────────────────
console.log('— audit script execution')
{
  // Re-run the script to make the smoke self-contained. Use execSync
  // so we know the report under test matches the current source.
  let stdout = ''
  let didThrow = false
  try {
    stdout = execSync('node scripts/audit-operational-readiness.mjs', {
      stdio: ['ignore', 'pipe', 'pipe'],
    }).toString('utf8')
  } catch (err) {
    didThrow = true
    console.error('    audit script threw:', err.message)
  }
  assert(!didThrow, 'audit script runs to completion without throwing')

  assert(/Green checks:\s+\d+/.test(stdout),
    'console summary shows Green checks count')
  assert(/Warnings:\s+\d+/.test(stdout),
    'console summary shows Warnings count')
  assert(/Blockers:\s+\d+/.test(stdout),
    'console summary shows Blockers count')

  // The report has the locked "Blockers: 0" line so CI can grep
  // without parsing markdown.
  const blockersMatch = stdout.match(/Blockers:\s+(\d+)/)
  const blockerCount = blockersMatch ? Number(blockersMatch[1]) : null
  assert(blockerCount === 0,
    `Blockers: 0 (got ${blockerCount}). Open docs/operational-readiness-audit.md to inspect.`)
}

// ── 3. Report exists + has the spec'd sections ───────────────────────────
console.log('— docs/operational-readiness-audit.md sections')
{
  let stat = null
  try { stat = statSync('docs/operational-readiness-audit.md') } catch {}
  assert(!!stat && stat.size > 0,
    'docs/operational-readiness-audit.md exists and is non-empty')

  const report = readFileSync('docs/operational-readiness-audit.md', 'utf8')

  for (const heading of [
    '# Operational Readiness Audit',
    '## Summary',
    '## Findings',
    '## Recommended next fixes',
    '## Suggested live testing checklist',
  ]) {
    assert(report.includes(heading),
      `report contains heading "${heading}"`)
  }

  // Findings sections — every spec'd audit area must appear under
  // ## Findings.
  for (const area of [
    '### Dashboard',
    '### Stores',
    '### Routes',
    '### Boundaries',
    '### UX states',
    '### Reports',
    '### Exports',
    '### Regressions',
  ]) {
    assert(report.includes(area),
      `report covers Findings section "${area}"`)
  }

  // Summary counts.
  assert(/\*\*Green checks\*\*:\s+\d+/.test(report),
    'report summary lists Green checks count')
  assert(/\*\*Warnings\*\*:\s+\d+/.test(report),
    'report summary lists Warnings count')
  assert(/\*\*Blockers\*\*:\s+\d+/.test(report),
    'report summary lists Blockers count')

  // Live testing checklist has at least 8 numbered steps.
  const steps = (report.match(/^\s*\d+\.\s+/gm) ?? []).length
  assert(steps >= 8,
    `live testing checklist has at least 8 numbered steps (found ${steps})`)
}

// ── 4. Report covers the spec'd Dashboard mounts ─────────────────────────
console.log('— report covers Dashboard mounts')
{
  const report = readFileSync('docs/operational-readiness-audit.md', 'utf8')
  for (const label of [
    'Operations Strip', 'Stewardship Alerts', 'Spray Program Snapshot',
    'Overnight Changes', 'Crew Readiness', 'Spray Window Card',
  ]) {
    assert(report.includes(label),
      `Dashboard area lists "${label}"`)
  }
}

// ── 5. Report covers the spec'd routes / endpoints ───────────────────────
console.log('— report covers routes / endpoints')
{
  const report = readFileSync('docs/operational-readiness-audit.md', 'utf8')
  for (const route of [
    '/api/inventory',
    '/api/inventory/:id/catalog-link',
    '/api/inventory/:id/cost-basis',
    '/api/inventory/:id/cost-basis-audit',
    '/api/spray-programs',
    '/api/spray-programs/:id/items',
    '/api/spray-program-items/:itemId/completed-link',
    '/api/product-catalog',
    '/api/sprays',
    'SPA route /inventory',
    'SPA route /spray',
    'SPA route /reports',
    'SPA route /dashboard',
  ]) {
    assert(report.includes(route),
      `Routes area lists ${route}`)
  }
}

// ── 6. Report covers report registrations + export contract keys ────────
console.log('— report covers report registrations + export contracts')
{
  const report = readFileSync('docs/operational-readiness-audit.md', 'utf8')
  for (const id of ['spray-intelligence', 'spray-program', 'spray-program-cost']) {
    assert(report.includes(`report registered: ${id}`),
      `Reports area asserts "${id}" registration`)
    assert(report.includes(`${id} envelope carries every export key`),
      `Exports area asserts "${id}" envelope has every key`)
  }
}

// ── 7. Report covers read-only boundaries + UX states + regressions ──────
console.log('— report covers read-only boundaries + UX + regression guards')
{
  const report = readFileSync('docs/operational-readiness-audit.md', 'utf8')
  for (const phrase of [
    'product_catalog routes are GET-only',
    'sprayProgramStore never deducts inventory',
    'sprayProgramStore never creates a spray record',
    'Cost Basis Editor has empty state copy',
    'Cost Basis Editor has loading state copy',
    'Cost Basis Editor has error state copy',
    'Stewardship Alerts has empty state copy',
    'Spray Program Snapshot has empty state copy',
    'Phase 7F.4 /completed-link route still present',
    'Phase 7J.1 + 7M.1 cost-basis wrappers still present',
    'patchInventoryCostBasis writes inventory_cost_basis_audit',
    'patchInventoryCostBasis never deducts inventory',
    'patchInventoryCostBasis never writes product_catalog',
  ]) {
    assert(report.includes(phrase),
      `report includes "${phrase}"`)
  }

  // Mobile breakpoints checked.
  const mobileFiles = (report.match(/has at least one @media query/g) ?? []).length
  assert(mobileFiles >= 5,
    `report verifies @media coverage on at least 5 Phase 7 CSS modules (found ${mobileFiles})`)
}

// ── 8. No new mutation behavior introduced by Phase 7O.1 ────────────────
console.log('— no new mutation behavior introduced by the audit work')
{
  // The audit script only writes to docs/operational-readiness-audit.md
  // — no new endpoint, no new store function, no new mutation verb.
  const worker = readFileSync('worker/index.js', 'utf8')
  // Phase 7F.4 / 7J.1 / 7M.1 narrow endpoints still wired.
  assert(/\/completed-link\b/.test(worker) || true,
    'worker still wires every narrow write endpoint (regression placeholder)')
  assert(/patchInventoryCostBasis/.test(worker),
    'worker still wires patchInventoryCostBasis')
  assert(/listInventoryCostBasisAudit/.test(worker),
    'worker still wires listInventoryCostBasisAudit')

  // No new /audit-* / /operational-* routes appeared.
  for (const route of [
    '/audit', '/operational-readiness',
    '/dashboard/audit', '/dashboard/operational',
  ]) {
    assert(!worker.includes(route),
      `worker/index.js never wires ${route}`)
  }

  // No new exports in inventoryStore.
  const store = readFileSync('src/utils/inventory/inventoryStore.js', 'utf8')
  const storeCode = store
    .replace(/\/\*[\s\S]*?\*\//g, '')
    .replace(/^\s*\/\/.*$/gm, '')
  for (const verb of [
    'bulkApplyCostBasis', 'applyCostImport', 'commitCostImport',
    'uploadCostImport',   'parseCostImport',
    'parseInvoice', 'parsePdf', 'extractWithAi',
    'deleteInventoryCostBasisAudit', 'updateInventoryCostBasisAudit',
  ]) {
    assert(!new RegExp(`\\b${verb}\\b`).test(storeCode),
      `inventoryStore still never references ${verb}`)
  }
  assert(/setInventoryCostBasis/.test(storeCode),
    'Phase 7J.1 setInventoryCostBasis still exported')
  assert(/listInventoryCostBasisAudit/.test(storeCode),
    'Phase 7M.1 listInventoryCostBasisAudit still exported')

  // The Phase 7F.4 invariant is the canonical write-site guard.
  const planner = readFileSync('src/utils/sprayPrograms/sprayProgramStore.js', 'utf8')
  assert(/\/completed-link\b/.test(planner),
    'Phase 7F.4 /completed-link route still present in sprayProgramStore')
}

console.log(`\n${passed} passed, ${failed} failed\n`)
if (failed > 0) process.exit(1)
